DDL:
DROP TABLE IF EXISTS DIM_EDUCATION_ATTAINMENT_ADULTS CASCADE;
CREATE TABLE DIM_EDUCATION_ATTAINMENT_ADULTS (
	EDUCATION_ADULTS_ID BIGINT PRIMARY KEY,
	HIGHEST_EDUCATION_LEVEL_AMONG_ADULTS_21_PLUS BIGINT,
	HIGHEST_EDUCATION_LEVEL_AMONG_FEMALES_21_PLUS BIGINT,
	HIGHEST_EDUCATION_LEVEL_AMONG_MALES_21_PLUS BIGINT
);

DROP TABLE IF EXISTS DIM_GEOGRAPHY CASCADE;
CREATE TABLE DIM_GEOGRAPHY (
	GEOGRAPHY_ID BIGINT PRIMARY KEY,
	STATE VARCHAR(50),
	DISTRICT VARCHAR(50),
	PSU_VILLAGE_OR_NEIGHBORHOOD_CODE BIGINT,
	CENSUS_2001_URBAN_RURAL_FLAG VARCHAR(50)
);

DROP TABLE IF EXISTS DIM_HOUSEHOLD_SOCIOECONOMIC CASCADE;
CREATE TABLE DIM_HOUSEHOLD_SOCIOECONOMIC (
	SOCIOECONOMIC_ID BIGINT PRIMARY KEY,
	CASTE_RELIGION_GROUP_8_CATEGORY VARCHAR(30),
	HOUSEHOLD_ASSETS_INDEX BIGINT
);

DROP TABLE IF EXISTS DIM_SURVEY_METHODOLOGY CASCADE;
CREATE TABLE DIM_SURVEY_METHODOLOGY (
	SURVEY_METHODOLOGY_ID BIGINT PRIMARY KEY,
	SURVEY_DESIGN_WEIGHT DOUBLE PRECISION,
	IS_REINTERVIEW_HOUSEHOLD VARCHAR(50)
);

DROP TABLE IF EXISTS FACT_HOUSEHOLD_POVERTY_METRICS CASCADE;
CREATE TABLE FACT_HOUSEHOLD_POVERTY_METRICS (
	HOUSEHOLD_POVERTY_METRICS_ID BIGINT PRIMARY KEY,
	HOUSEHOLD_ID BIGINT,
	MONTHLY_CONSUMPTION_PER_CAPITA DOUBLE PRECISION,
	PER_CAPITA_POVERTY_LINE DOUBLE PRECISION,
	BELOW_POVERTY_LINE_INDICATOR VARCHAR(20)
);
